import './Post.css'
import React, { Component } from 'react'
import { Link } from 'react-router-dom';
import { News } from '../../db.js'

export default class Post extends Component {
    constructor(props) {
        super(props)

        this.state = {
            actBtn: false
        }
    }

    render() {
        const { img, id, title, tags } = this.props.list

        return (
            <div className="card-post n-s" onMouseMove={() => { this.setState({ actBtn: true }) }} onMouseOut={() => { this.setState({ actBtn: false }) }}>
                {this.props.x ? <Link to="/"><div className={this.state.actBtn ? "x-class" : "d-none"} onClick={() => {
                    let idComp = `${id}`
                    News(idComp, "delete")
                }}>Удалить</div></Link> : <div></div>}
                {this.props.x_l ? <Link to="/"><div className={this.state.actBtn ? "x-class" : "d-none"} onClick={() => {
                    let idComp = `${id}`
                    News(idComp, "delete")
                }}>Удалить</div></Link> : <div></div>}
                <Link to={`/posts/${id}`} id={id}>
                    <div className={this.state.actBtn ? "tags-block" : "d-none"}>{tags}</div>
                    <img className="img-post" width="100%" src={img} alt={`title: ${title}`} />
                </Link >
            </div>
        )
    }
}
